import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-zlLwmkyI.js";var s={class:`ant-doc vp-doc`},c=a({__name:`contributing.en-US`,setup(a,{expose:c}){let l={title:`Contributing`,frontmatter:{title:`Contributing`},headers:[{level:2,title:`Code of Conduct`,slug:`code-of-conduct`,link:`#code-of-conduct`,children:[]},{level:2,title:`Transparent Development`,slug:`transparent-development`,link:`#transparent-development`,children:[]},{level:2,title:`Branch Management`,slug:`branch-management`,link:`#branch-management`,children:[]},{level:2,title:`First Contribution`,slug:`first-contribution`,link:`#first-contribution`,children:[]},{level:2,title:`Pull Request`,slug:`pull-request`,link:`#pull-request`,children:[]},{level:2,title:`Development Workflow`,slug:`development-workflow`,link:`#development-workflow`,children:[]},{level:2,title:`Acknowledgements`,slug:`acknowledgements`,link:`#acknowledgements`,children:[]}],description:``},u={title:`Contributing`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>This guide will help you understand how to contribute to ProComponents of Vue. Please take a few minutes to read this guide before submitting an issue or pull request.</p><h2 id="code-of-conduct" tabindex="-1">Code of Conduct <a class="header-anchor" href="#code-of-conduct" aria-label="Permalink to &quot;Code of Conduct&quot;">ŌĆŗ</a></h2><p>We use the same <a href="https://github.com/antdv-next/antdv-next/blob/main/CODE_OF_CONDUCT.md">Code of Conduct</a> as the Ant Design community. We hope all contributors will abide by it. Please take the time to read it thoroughly to ensure you understand what is and isnŌĆÖt allowed.</p><h2 id="transparent-development" tabindex="-1">Transparent Development <a class="header-anchor" href="#transparent-development" aria-label="Permalink to &quot;Transparent Development&quot;">ŌĆŗ</a></h2><p>All our development work is done on <a href="https://github.com/antdv-next/antdv-next">Github</a>. Whether itŌĆÖs a pull request from a team member or a community contributor, all pull requests must go through the same review process.</p><h2 id="branch-management" tabindex="-1">Branch Management <a class="header-anchor" href="#branch-management" aria-label="Permalink to &quot;Branch Management&quot;">ŌĆŗ</a></h2><p>We currently maintain two long-term branches: <code>main</code> and <code>feat</code>. If you need to fix a bug, please send a pull request to <code>main</code>. We will release a <code>patch</code> version from <code>main</code> every period of time (at most one month). If you need to add a new feature pull request, please base it on the <code>feat</code> branch. We will try to merge <code>feat</code> into <code>main</code> within two months and release a <code>minor</code> version containing new features.</p><div class="info custom-block"><p class="custom-block-title">Why is the cycle uncertain?</p><p>We donŌĆÖt have a large team like Ant Design to support frequent version releases, so we can only release new versions as quickly as possible while ensuring quality. We hope everyone understands.</p></div><h2 id="first-contribution" tabindex="-1">First Contribution <a class="header-anchor" href="#first-contribution" aria-label="Permalink to &quot;First Contribution&quot;">ŌĆŗ</a></h2><p>If youŌĆÖre not sure how to submit a Pull Request on GitHub, you can read the following article to learn:</p><p><a href="https://opensource.guide/how-to-contribute/">How to Contribute on GitHub</a></p><p>To help you get started with your first attempt, weŌĆÖve marked some relatively easy-to-fix bugs and small features with <a href="https://github.com/antdv-next/antdv-next/issues?q=is%3Aissue+is%3Aopen+label%3A%22good+first+issue%22">good first issues</a>. These issues can serve as a good first attempt.</p><p>If you plan to start working on an issue, please check the comments below the issue first to make sure no one else is working on it. If no one is currently working on it, you can leave a comment to let others know you will be handling this issue to avoid duplicate work.</p><p>If someone previously commented that they would handle the issue but there has been no activity for a week or two, you can also take over the issue, but you still need to leave a comment to inform others.</p><h2 id="pull-request" tabindex="-1">Pull Request <a class="header-anchor" href="#pull-request" aria-label="Permalink to &quot;Pull Request&quot;">ŌĆŗ</a></h2><p>The ProComponents of Vuents of Vue Team will pay attention to all pull requests. We will review and merge your code, and may also ask you to make some changes or tell you why we cannot accept such changes.</p><p><strong>Before you send a Pull Request</strong>, please make sure you follow these steps:</p><ol><li>Make changes based on the <a href="#branch-management">correct branch</a>.</li><li>Run <code>pnpm install</code> in the project root directory.</li><li>If you fixed a bug or added a new feature, please make sure to write corresponding tests. This is important.</li></ol><p>Since most of antdv-next is based on <code>vue-components</code>, sometimes you need to send a pull request to the <a href="https://github.com/antdv-next/vue-components">vue-components</a> repository. If you fix a bug, we will release a patch version as soon as possible after merging your changes, and then you just need to reinstall your dependencies to use the newly released version. If your pull request adds a new feature, after your changes are merged and a version is released, you also need to send a pull request to ProComponents of Vuents of Vue to upgrade the corresponding dependencies, documentation, and TypeScript type definitions.</p><h2 id="development-workflow" tabindex="-1">Development Workflow <a class="header-anchor" href="#development-workflow" aria-label="Permalink to &quot;Development Workflow&quot;">ŌĆŗ</a></h2><p>Our project is a monorepo by default, using <a href="https://pnpm.io/workspaces">pnpm workspace</a> to manage multiple sub-packages. So before you start contributing code, please make sure you understand the basic usage of pnpm workspace.</p><p>The following steps assume you have already installed and configured pnpm.</p><ol><li>Fork this repository to your personal account.</li><li>Clone your forked repository locally: <code>git clone https://github.com/xxx/antdv-next.git</code>.</li><li>Enter the project directory: <code>cd antdv-next</code>.</li><li>Install dependencies: <code>pnpm install</code>.</li><li>Run the development environment: <code>pnpm dev</code>.</li><li>Run code style check: <code>pnpm lint</code>.</li><li>Build the site: <code>pnpm build</code>.</li><li>Compile and build: <code>pnpm build:antdv</code>.</li></ol><h2 id="acknowledgements" tabindex="-1">Acknowledgements <a class="header-anchor" href="#acknowledgements" aria-label="Permalink to &quot;Acknowledgements&quot;">ŌĆŗ</a></h2><p>Thanks to all the friends who contributed code and documentation to ProComponents of Vuents of Vue. You make this project better! We look forward to more contributors joining this project to promote the develProComponents of VueProComponents of Vue together.</p><a href="https://github.com/antdv-next/antdv-next/graphs/contributors"><img src="https://contrib.rocks/image?repo=antdv-next/antdv-next&amp;max=100&amp;columns=15"></a>`,26)]]))}});export{c as default};